"""CSV Extractor: reads CSV sales data and returns list of record dicts.

Handles date parsing, field validation, and type conversion.
"""

import csv
import io
from datetime import datetime, timezone


def parse_date(date_str):
    """Parse a date string in YYYY-MM-DD or ISO-8601 format.

    Returns a datetime object.
    """
    if not date_str:
        return None
    date_str = date_str.strip()
    # BUG 1: Adds UTC timezone, but data is local time — should parse as-is
    for fmt in ('%Y-%m-%dT%H:%M:%S', '%Y-%m-%d'):
        try:
            dt = datetime.strptime(date_str, fmt)
            return dt.replace(tzinfo=timezone.utc)  # BUG: should not add tz
        except ValueError:
            continue
    return None


def extract(filepath_or_content, is_content=False):
    """Extract records from CSV file or string content.

    Returns a list of dicts with keys:
      date, customer_id, product_id, quantity, unit_price, currency

    Numeric fields (quantity, unit_price) are converted to float.
    """
    if is_content:
        content = filepath_or_content
    else:
        with open(filepath_or_content, 'r') as f:
            content = f.read()

    reader = csv.DictReader(io.StringIO(content))
    records = []
    for row in reader:
        record = {}
        for key, value in row.items():
            key = key.strip()
            if value is not None:
                value = value.strip()
            # BUG 7: Empty strings are NOT converted to None.
            # Downstream code does float(record['quantity']) which
            # raises ValueError on empty string.
            if key == 'date':
                record[key] = parse_date(value)
            elif key in ('quantity', 'unit_price'):
                try:
                    record[key] = float(value)
                except (ValueError, TypeError):
                    record[key] = value  # BUG 7: keeps empty str instead of None
            else:
                record[key] = value
        records.append(record)
    return records
